{"settings":"{
    // ================= VSCODE =================
    "database-client.autoSync": true,
    "workbench.iconTheme": "material-icon-theme",

    "editor.fontFamily": "Consolas, 'Courier New', monospace",

    "explorer.confirmDelete": false,
    "extensions.autoUpdate": "off",
    "workbench.startupEditor": "none",

    // ================= EDITOR CORE =================
    "multiCommand.commands": [
        {
            "command": "multiCommand.ctrlSelectLineUp",
            "sequence": ["cursorHome", "cursorEndSelect"]
        },
        {
            "command": "multiCommand.duplicateDown",
            "sequence": ["editor.action.copyLinesDownAction"]
        },
        {
            "command": "multiCommand.selectLineUpContinuous",
            "sequence": ["cursorUpSelect"]
        },
        {
            "command": "multiCommand.ctrlDOne",
            "sequence": ["removeSecondaryCursors", "editor.action.addSelectionToNextFindMatch"]
        }
    ],

    "editor.codeLens": true,
    "editor.colorDecoratorsActivatedOn": "hover",
    "editor.inlayHints.enabled": "on",
    "editor.linkedEditing": true,
    "editor.rulers": [
        {
            "column": 80,
            "color": "#00FF0010"
        },
        {
            "column": 100,
            "color": "#BDB76B15"
        },
        {
            "column": 120,
            "color": "#FA807219"
        }
    ],

    "editor.unicodeHighlight.includeComments": true,
    "editor.wordWrap": "off",

    // ================= INDENT =================
    "editor.tabSize": 4,
    "editor.insertSpaces": true,
    "editor.detectIndentation": false,

    // ================= WORKBENCH =================
    "workbench.colorTheme": "Visual Studio Dark - C++",

    "workbench.colorCustomizations": {
        "[Default Dark Modern]": {
            "tab.activeBorderTop": "#00FF00",
            "tab.unfocusedActiveBorderTop": "#00FF0088",
            "textCodeBlock.background": "#00000055"
        },
        "editor.wordHighlightStrongBorder": "#FF6347",
        "editor.wordHighlightBorder": "#FFD700",
        "editor.selectionHighlightBorder": "#A9A9A9"
    },
    "workbench.editor.revealIfOpen": true,
    "files.eol": "\n",
    "[bat]": {
        "files.eol": "\r\n"
    },
    "emmet.variables": {
        "lang": "pt"
    },

    // ================= FILE =================
    "files.insertFinalNewline": true,
    "files.trimTrailingWhitespace": true,
    "files.trimFinalNewlines": true,
    "files.autoGuessEncoding": true,

    // ================= DATABASE (MSSQL / DATABASE CLIENT) =================
    "mssql.connections": [],
    "mssql.connectionGroups": [
        {
            "name": "ROOT",
            "id": "67933EDC-FDC3-44D4-810B-7B0001A14FDD"
        }
    ],

    // ================= SECURITY =================
    "security.workspace.trust.untrustedFiles": "open",
    "security.promptForLocalFileProtocolHandling": false,
    "editor.unicodeHighlight.includeStrings": true,
    "editor.renderControlCharacters": false,

    // ================= GIT =================
    "git.autofetch": true,
    "git.openRepositoryInParentFolders": "never",

    "git.enableSmartCommit": true,
    "git.suggestSmartCommit": false,

    // ================= C++ / C =================
    "C_Cpp.intelliSenseEngine": "default",

    "C_Cpp.default.cStandard": "c17",
    "C_Cpp.default.cppStandard": "c++20",

    "C_Cpp.default.browse.limitSymbolsToIncludedHeaders": true,
    "C_Cpp.default.preferredPathSeparator": "/",
    "C_Cpp.errorSquiggles": "enabled",

    "clangd.arguments": [
        "--background-index",
        "--clang-tidy",
        "--completion-style=detailed"
    ],

    // Associações de arquivos
    "files.associations": {
        "*.h": "c",
        "*.hpp": "cpp",
        "*.tpp": "cpp"
    },
    "makefile.configureOnOpen": true,

    // ================= Run On Save =================
    "emeraldwalk.runonsave": {
        "commands": [
            {
                "match": "\\.c$",
                "cmd": "gcc *.c -std=c17 -Wall -Wextra -g -o app.exe"
            },
            {
                "match": "\\.cpp$|\\.cc$|\\.cxx$",
                "cmd": "g++ *.cpp -std=c++20 -Wall -Wextra -g -o app.exe"
            }
        ]
    },

    // ================= LIVE SERVER =================
    "liveServer.settings.CustomBrowser": "firefox",
    "liveServer.settings.donotVerifyTags": true,
    "liveServer.settings.AdvanceCustomBrowserCmdLine": "",
    "liveServer.settings.wait": 500,

    // ================= CODE RUNNER =================
    "code-runner.executorMap": {
        "rust": "cd $dir && rustc $fileName && ./$fileNameWithoutExt"
    },
    "code-runner.runInTerminal": true,
    "code-runner.clearPreviousOutput": true,

    "code-runner.ignoreSelection": true,
    "code-runner.saveFileBeforeRun": true,
    "code-runner.fileDirectoryAsCwd": true,
    "code-runner.preserveFocus": false,

    // ================= FORMATTER =================
    "prettier.enable": true,
    "prettier.requireConfig": false,
    "prettier.useEditorConfig": true,
    "prettier.tabWidth": 4,
    "prettier.useTabs": false,
    "prettier.printWidth": 120,
    "prettier.arrowParens": "always",
    "prettier.endOfLine": "lf",
    "prettier.quoteProps": "as-needed",
    "prettier.embeddedLanguageFormatting": "auto",
    "prettier.proseWrap": "preserve",

    "prettier.singleQuote": false,
    "prettier.jsxSingleQuote": false,

    "prettier.htmlWhitespaceSensitivity": "css",
    "prettier.semi": true,

    "prettier.trailingComma": "all",
    "prettier.bracketSpacing": true,

    "editor.defaultFormatter": "esbenp.prettier-vscode",

    "[cpp]": {
        "editor.defaultFormatter": "ms-vscode.cpptools",
        "editor.tabSize": 4,
        "editor.insertSpaces": true
    },

    "[c]": {
        "editor.defaultFormatter": "ms-vscode.cpptools",
        "editor.tabSize": 4,
        "editor.insertSpaces": true
    },

    "[java]": {
        "editor.defaultFormatter": "redhat.java",
        "editor.tabSize": 4,
        "editor.insertSpaces": true
    },

    "[rust]": {
        "editor.defaultFormatter": "rust-lang.rust-analyzer"
    },

    "[python]": {
        "editor.defaultFormatter": "charliermarsh.ruff"
    },

    "[javascript]": {
        "editor.defaultFormatter": "esbenp.prettier-vscode"
    },

    "[typescript]": {
        "editor.defaultFormatter": "esbenp.prettier-vscode"
    },

    "[json]": {
        "editor.defaultFormatter": "esbenp.prettier-vscode"
    },

    "[html]": {
        "editor.defaultFormatter": "esbenp.prettier-vscode"
    },

    "[css]": {
        "editor.defaultFormatter": "esbenp.prettier-vscode"
    },

    // ================= PERFORMANCE =================
    "editor.minimap.enabled": false,
    "diffEditor.hideUnchangedRegions.enabled": true,
    "terminal.integrated.enablePersistentSessions": false,
    "files.watcherExclude": {
        "**/.git/**": true,
        "**/node_modules/**": true,
        "**/target/**": true,
        "**/build/**": true
    },

    // ================= DRAW.IO =================
    "hediet.vscode-drawio.resizeImages": null,
    "hediet.vscode-drawio.theme": "min",
    "hediet.vscode-drawio.appearance": "dark",

    // ================= IA COPLIT =================
    "editor.inlineSuggest.enabled": false,

    "chat.mcp.discovery.enabled": {
        "claude-desktop": true,
        "windsurf": true,
        "cursor-global": true,
        "cursor-workspace": true
    },

    "chat.alternativeToolAction.enabled": true,
    "chat.mcp.gallery.enabled": true,
    "chat.mcp.serverSampling": {
        "enabled": true,
        "mode": "conservative",
        "Global in Code: local-filesystem": {
            "allowedModels": [
                "copilot/claude-opus-4.6",
                "copilot/gemini-2.5-pro",
                "copilot/gemini-3-pro-preview",
                "copilot/gpt-4o",
                "copilot/gpt-5-mini",
                "copilot/gpt-5.2"
            ]
        }
    },

    "chat.viewSessions.orientation": "stacked",

    // ================= CLINE =================
        "cline.vsCodeLmModelSelector": {
            "vendor": "copilot",
            "family": "gpt-5"
        },

        "cline.mcp.enabled": true,

        // mantém contexto maior
        "cline.autoApprove": {
            "enabled": false
        },

        // terminal
        "cline.allowedCommands": [
            "git",
            "python",
            "pip",
            "npm",
            "dnf",
            "rpm",
            "rpmbuild"
        ],

    // ================= VSCORD =================
    "vscord.app.privacyMode.enable": true,
    "vscord.status.workspace.enabled": false,
    "vscord.status.problems.enabled": false,
    "vscord.status.state.debugging.enabled": false,
    "vscord.status.state.idle.enabled": false,

    "vscord.status.image.small.viewing.text": "Conding ☕ {app_name}",
    "vscord.status.image.large.editing.text": "Conding in {LANG} file",

    "vscord.status.details.text.viewing": "☕️ Coding in {app_name}",
    "vscord.status.state.text.editing": "☕️ Coding in {LANG}",
    "vscord.status.state.text.debugging": "☕️ Coding in {app_name}",
    "vscord.status.state.text.idle": "☕️ Coding in {LANG}",

    "update.showReleaseNotes": false,

    "github.copilot.nextEditSuggestions.enabled": true,
    "github.copilot.chat.tools.memory.enabled": true,

    // ================= JAVA =================
    "editor.tokenColorCustomizations": {
        "textMateRules": [
            {
                "scope": "support.type.log-level.error.tomcat",
                "settings": {
                    "foreground": "#D32F2F",
                    "fontStyle": "bold"
                }
            },
            {
                "scope": "support.type.log-level.warn.tomcat",
                "settings": {
                    "foreground": "#FF6B6B"
                }
            },
            {
                "scope": "support.type.log-level.success.tomcat",
                "settings": {
                    "foreground": "#73C991"
                }
            }
        ]
    },

    "java.completion.filteredTypes": ["org.stringtemplate.*","java.atw.List","sun.net.www.content.text.*"],

    "jdk.jdkhome": "/home/quitto/.sdkman/candidates/java/current",
    "redhat.telemetry.enabled": false,
    "jdk.telemetry.enabled": false,
    "java.help.collectErrorLog": true,
    "java.compile.nullAnalysis.mode": "disabled",

    // Formater
    "java.format.settings.url": "file:///C:/Users/Quitto/AppData/Roaming/Code/User/formater/eclipse-formatter-custom.xml",
    "java.format.settings.profile": "QuittoStyle",

    "[java]": {
        "editor.defaultFormatter": "redhat.java",
        "editor.formatOnSave": false,
    },

    "java.errors.incompleteClasspath.severity": "ignore",
    "java.compile.unusedLocal": "ignore",
    "java.compile.unusedPrivate": "ignore",
    "java.compile.unusedImport": "warning",
    "java.compile.deadCode": "warning",
    "java.compile.unusedParameter": "warning",
    "java.referencesCodeLens.enabled": false,
    "java.implementationsCodeLens.enabled": false,
    "java.referencesCodeLens.enabled": false,
    "java.implementationsCodeLens.enabled": false,
    "java.configuration.updateBuildConfiguration": "automatic",
    "java.debug.settings.hotCodeReplace": "auto",
    "java.dependency.packagePresentation": "hierarchical",
    "java.maxConcurrentBuilds": 8,
    "java.sources.organizeImports.staticStarThreshold": 1,

    "spring.tools.codeLens.enabled": true,

    "java.test.config": {
        "vmArgs": ["-Dstdout.encoding=UTF-8", "-Dstderr.encoding=UTF-8"]
    },

    "maven.terminal.customEnv": [
        {
            "environmentVariable": "JAVA_HOME",
            "value": "/home/quitto/.sdkman/candidates/java/current"
        }
    ],

    // ================= TERMINAL =================
    "terminal.integrated.sendKeybindingsToShell": false,
    "terminal.integrated.defaultProfile.linux": "bash",
    "terminal.integrated.fontFamily": "'JetBrains Mono','FiraCode Nerd Font','CommitMono Nerd Font', monospace",
    "terminal.integrated.gpuAcceleration": "on",
    "terminal.integrated.tabs.hideCondition": "never",
    "terminal.integrated.shellIntegration.enabled": true,
    "terminal.integrated.profiles.linux": {
        "bash": {
            "path": "/bin/bash",
            "args": [],
            "icon": "terminal"
        },

        "JavaSE-21 LTS": {
            "path": "/bin/bash",
            "args": [],
            "env": {
                "JAVA_HOME": "/home/quitto/.sdkman/candidates/java/current",
                "PATH": "/home/quitto/.sdkman/candidates/java/current/bin:${env:PATH}",
                "JAVA_TOOL_OPTIONS": "-Dstdout.encoding=UTF-8 -Dstderr.encoding=UTF-8"
            }
        },

        "JavaSE-25 LTS": {
            "path": "/bin/bash",
            "args": [],
            "env": {
                "JAVA_HOME": "/home/quitto/.sdkman/candidates/java/current",
                "PATH": "/home/quitto/.sdkman/candidates/java/current/bin:${env:PATH}",
                "JAVA_TOOL_OPTIONS": "-Dstdout.encoding=UTF-8 -Dstderr.encoding=UTF-8"
            }
        }
    },
    "terminal.integrated.automationProfile.linux": {
        "path": "bash"
    },

    // ================= CSPELL =================
    "cSpell.diagnosticLevel": "Hint",

    // ================= TRAILING SPACES =================
    "trailing-spaces.backgroundColor": "rgba(255,0,0,0.1)",
    "trailing-spaces.includeEmptyLines": false,

    // ================= POWERSHELL =================
    "powershell.promptToUpdatePowerShell": false,

    // ================= MARKDOWN =================
    "markdown-preview-enhanced.previewTheme": "atom-dark.css",
    "[markdown]": {
        "editor.wordWrap": "on"
    },
    "[plaintext]": {
        "editor.wordWrap": "on"
    },

    // ================= QUARTO =================
    "[quarto]": {
        "editor.wordWrap": "bounded",
        "editor.wordWrapColumn": 100
    },
    "quarto.render.renderOnSave": false,

    "code-runner.executorMapByFileExtension": {
        ".qmd": "/home/quitto/Research/ABNT/abnt.sh \"$fullFileName\""
    },

    "yaml.disableSchemaDetection": [
        "**/.github/workflows/*.yml",
        "**/.github/workflows/*.yaml",
        "**/.gitea/workflows/*.yml",
        "**/.gitea/workflows/*.yaml",
        "**/.forgejo/workflows/*.yml",
        "**/.forgejo/workflows/*.yaml"
    ],
}"}
